async (params, browser) => {
  // Open template page
  await browser.open(`${params.template_url}`)

  // Wait for template page to load
  await browser.waitForSelector('h1, [role=\'heading\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract template details
  const template_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [role="heading"]'); const metaDesc = document.querySelector('meta[name="description"]'); const descEl = document.querySelector('main p, article p'); const breadcrumbs = document.querySelectorAll('nav a, [aria-label="breadcrumb"] a'); const categoryEl = breadcrumbs.length > 0 ? breadcrumbs[breadcrumbs.length - 1] : null; const imgEl = document.querySelector('main img, article img, [role="img"]'); const proEl = document.querySelector('[aria-label*="Pro"], [aria-label*="premium"]'); const tagEls = document.querySelectorAll('a[href*="/templates/s/"]'); const tags = []; tagEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 50 && !tags.includes(t)) tags.push(t); }); const relatedEls = document.querySelectorAll('a[href*="/templates/"]'); const related = []; const seen = new Set(); seen.add(window.location.href); relatedEls.forEach(function(el) { if (related.length >= 6) return; const href = el.href || ''; if (!href || seen.has(href)) return; seen.add(href); const iEl = el.querySelector('img'); const label = el.getAttribute('aria-label') || ''; const tEl = el.querySelector('h3, h4, [aria-label]'); related.push({ title: label || (tEl ? (tEl.getAttribute('aria-label') || tEl.textContent.trim()) : ''), url: href, image: iEl ? iEl.getAttribute('src') : '' }); }); return { title: titleEl ? titleEl.textContent.trim() : '', description: metaDesc ? metaDesc.getAttribute('content') : (descEl ? descEl.textContent.trim().substring(0, 1000) : ''), category: categoryEl ? categoryEl.textContent.trim() : '', is_premium: !!proEl, tags: tags.slice(0, 10), image: imgEl ? imgEl.getAttribute('src') : '', related_templates: related, url: window.location.href }`)

  return template_data
}
